__global__ void naive_gemm_nn(
    const half* __restrict__ A,  // M x K, row-major
    const half* __restrict__ B,  // K x N, row-major
    float* __restrict__ C,       // M x N, row-major
    int M, int N, int K,
    float alpha, float beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            // A[row,k] = A[row*K + k] - consecutive in k (coalesced for threads along k)
            // B[k,col] = B[k*N + col] - consecutive in col (coalesced for threads along col)
            sum += __half2float(A[row * K + k]) * __half2float(B[k * N + col]);
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_gemm_nt(
    const half* __restrict__ A,  // M x K, row-major
    const half* __restrict__ B,  // N x K, col-major (or equivalently K x N row-major, accessed as B^T)
    float* __restrict__ C,       // M x N, row-major
    int M, int N, int K,
    float alpha, float beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            // A[row,k] = A[row*K + k]
            // B^T[k,col] = B[col,k] = B[col*K + k] (B stored as NxK col-major = KxN row-major transposed)
            sum += __half2float(A[row * K + k]) * __half2float(B[col * K + k]);
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_gemm_tn(
    const half* __restrict__ A,  // K x M, col-major (A^T is M x K)
    const half* __restrict__ B,  // K x N, row-major
    float* __restrict__ C,       // M x N, row-major
    int M, int N, int K,
    float alpha, float beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            // A^T[row,k] = A[k,row] = A[k + row*K] (A stored col-major KxM)
            // B[k,col] = B[k*N + col]
            sum += __half2float(A[k + row * K]) * __half2float(B[k * N + col]);
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_gemm_tt(
    const half* __restrict__ A,  // K x M, col-major (A^T is M x K)
    const half* __restrict__ B,  // N x K, col-major (B^T is K x N)
    float* __restrict__ C,       // M x N, row-major
    int M, int N, int K,
    float alpha, float beta) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;
    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            // A^T[row,k] = A[k,row] = A[k + row*K]
            // B^T[k,col] = B[col,k] = B[col + k*N]
            sum += __half2float(A[k + row * K]) * __half2float(B[col + k * N]);
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}
